const sources = [{key:'TechCrunch',icon:'🐦',label:'TechCrunch 热门'},{key:'HackerNews',icon:'🔶',label:'HackerNews 热门'},{key:'ProductHunt',icon:'🚀',label:'Product Hunt 今日新品'}];
const dMap = new Map();for(const d of allData)dMap.set(d.source,d);
const results = sources.map(s=>{const r=dMap.get(s.key)||{items:[],error:null};return{...s,...r};});
const total = results.reduce((s,r)=>s+(r.items?.length||0),0);
const errors = results.filter(r=>r.error).map(r=>({source:r.key,msg:r.error}));
const now = new Date();const bj = new Date(now.getTime()+8*3600000);
const ts = bj.toISOString().replace('T',' ').slice(0,19)+' (北京时间)';
const transStats = allData.find(d=>d._translationStats)?._translationStats || {};

// 清理描述字段
function cleanDesc(desc, source) {
  if (!desc) return '';
  if (source === 'HackerNews') return '';
  if (source === 'ProductHunt') {
    return desc.replace(/\s*(Discussion|讨论)\s*\|\s*(Link|链接)\s*/g, '').trim();
  }
  return desc.substring(0, 80);
}

// 格式化运行时间
const startTime = transStats.startTime || '-';
const endTime = transStats.endTime || '-';
const timeRange = startTime + '~' + endTime.split(' ')[1];

// 获取翻译服务IP
const host = transStats.host || '';
const hostIp = host.includes('87') ? '87' : host.includes('102') ? '102' : '-';

let md = '';
md += `**📊 运行统计**\n`;
md += `⏰ 运行时间: ${timeRange}\n`;
md += `🤖 翻译服务: ${transStats.model || '未配置'} (${hostIp})\n`;
md += `📄 翻译结果: ${transStats.translatedCount || 0}/${transStats.totalTexts || 0}条成功\n`;
md += `⏱️ 翻译耗时: ${transStats.durationFormatted || '-'}\n`;
md += `📡 数据源: TC:${results.find(r=>r.key==='TechCrunch')?.items?.length || 0} HN:${results.find(r=>r.key==='HackerNews')?.items?.length || 0} PH:${results.find(r=>r.key==='ProductHunt')?.items?.length || 0}\n`;
md += `\n---\n`;
if(errors.length===0)md+=`**✅ 所有数据源获取成功** | 📊 总文章数: ${total} 条\n\n`;
else{md+=`**⚠️ 数据获取状态**\n✅ 成功: ${results.length-errors.length}/${results.length}\n❌ 失败: ${errors.length}/${results.length}\n📊 总文章数: ${total} 条\n\n`;errors.forEach(e=>{md+=`- **${e.source}**: ${e.msg}\n`;});md+='\n';}
results.forEach(r=>{md+=`\n---\n**${r.icon} ${r.label}**`;if(r.error){md+=` ❌ ${r.error}\n\n`;return;}const c=r.items?.length||0;md+=` (${c}条)\n`;if(c===0){md+='> 暂无数据\n\n';return;}(r.items||[]).forEach((it,i)=>{const t=it.title||'(无标题)';const d=cleanDesc(it.description, r.key);const dStr=d?` — ${d}`:'';const sc=r.key==='HackerNews'&&it.points?` (${it.points}分)`:'';const lk=it.link?` [🔗查看详情](${it.link})`:'';md+=`${i+1}. **${t}**${sc}${dStr}${lk}\n`;});md+='\n';});
md+=`\n---\n*由 n8n 自动生成 | ${ts}*`;
return [{json:{markdown:md,date,totalItems:total,errorCount:errors.length,errors,feishuWebhook:config.feishuWebhook,translationStats:transStats}}];

const data = $input.first().json;
const md = data.markdown || '';
const trunc = md.length > 8000 ? md.substring(0, 7900) + '\n\n... (已截断)' : md;
const title = data.errorCount > 0 ? `📊 科技资讯日报 (⚠️ ${data.errorCount}个源失败)` : '📊 科技资讯日报';
const tmpl = data.errorCount > 0 ? 'red' : 'blue';
const payload = {msg_type:"interactive",card:{schema:"2.0",config:{wide_screen_mode:true},header:{title:{tag:"plain_text",content:`${title} ${data.date}`},template:tmpl},body:{elements:[{tag:"markdown",content:trunc}]}}};
return [{json:{webhookUrl:data.feishuWebhook,payload,date:data.date,totalItems:data.totalItems,errorCount:data.errorCount}}];

// 从初始化配置获取日期
const initConfig = $('初始化配置').first().json;
const date = initConfig?.date || '未知日期';

// 从格式化日报获取统计
const formatData = $('格式化日报').first().json;
const totalItems = formatData?.totalItems || 0;
const errorCount = formatData?.errorCount || 0;
const transStats = formatData?.translationStats || {};

// 从当前输入获取飞书响应
const feishuResp = $input.first().json;
let feishuStatus = '未执行';
if (feishuResp) {
    const code = feishuResp.code ?? feishuResp.StatusCode;
    if (code === 0) feishuStatus = '✅ 发送成功';
    else if (code !== undefined) feishuStatus = `❌ API错误: ${code}`;
    else if (feishuResp.statusCode) feishuStatus = feishuResp.statusCode === 200 ? '✅ 发送成功' : `❌ HTTP错误: ${feishuResp.statusCode}`;
}

// 翻译状态
const transStatus = transStats.model ? `${transStats.model} ${transStats.translatedCount}/${transStats.totalTexts}条` : '未配置';

return [{ json: { 
    message: `✅ 日报生成完成: ${date}`, 
    totalItems, 
    errors: errorCount > 0 ? `${errorCount}个数据源失败` : '无', 
    feishuStatus,
    translation: transStatus,
    translationTime: transStats.durationFormatted || '-',
    startTime: transStats.startTime || '-',
    endTime: transStats.endTime || '-'
} }];
